mapper.sql:
from aiw_news_article_relation r
where 1 = 1

    and r.article_biz_id = #{criteria.articleBizId}


    and r.theme_code = #{criteria.themeCode}


    and r.product_code = #{criteria.productCode}


    and r.relation_type = #{criteria.relationType}

mapper.select:
select r.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
